/**
 * DepthAnythingVideoInput
 *
 * Input schema for video depth estimation.
 */
export type DepthAnythingVideoInput = {
  /**
   * Resolution
   *
   * Output resolution. 'auto' preserves input (max 1080p). Options: 'auto', '360p', '480p', '720p', '1080p'.
   */
  resolution?: "auto" | "360p" | "480p" | "720p" | "1080p";
  /**
   * Video Url
   *
   * URL of the input video to estimate depth for.
   */
  video_url: string | Blob | File;
  /**
   * Colormap
   *
   * Colormap for depth visualization. 'turbo' (recommended) shows near=warm, far=cool. 'grayscale' for raw normalized depth. 'inferno'/'magma' for perceptually uniform. 'viridis' for colorblind-friendly.
   */
  colormap?: "grayscale" | "turbo" | "inferno" | "magma" | "viridis";
  /**
   * Output Fps
   *
   * Output video FPS. None = same as input.
   */
  output_fps?: number | unknown;
  /**
   * Model
   *
   * Depth estimation model size. VDA-Large = best quality, VDA-Small = fastest.
   */
  model?: "VDA-Small" | "VDA-Base" | "VDA-Large";
  /**
   * Include Raw Depths
   *
   * Export raw float32 depths as .npz file with: 'depths' [N,H,W], 'min_depth', 'max_depth', 'fps', 'model', 'shape'.
   */
  include_raw_depths?: boolean;
  /**
   * Max Frames
   *
   * Max frames to process. None = all frames.
   */
  max_frames?: number | unknown;
  /**
   * Side By Side
   *
   * Output original | depth comparison video.
   */
  side_by_side?: boolean;
};

